import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"4.永生羽衣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/梦火将熄/4.永生羽衣.md","filePath":"4.资源分区/1.血统与训练/3.心智类/梦火将熄/4.永生羽衣.md"}'),o={name:"4.资源分区/1.血统与训练/3.心智类/梦火将熄/4.永生羽衣.md"};function p(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"_4-永生羽衣",tabindex:"-1"},[n("4.永生羽衣 "),r("a",{class:"header-anchor",href:"#_4-永生羽衣","aria-label":'Permalink to "4.永生羽衣"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),s('<h1 id="永生羽衣" tabindex="-1">永生羽衣 <a class="header-anchor" href="#永生羽衣" aria-label="Permalink to &quot;永生羽衣&quot;">​</a></h1><p>永生羽衣<br> 这是一件金红色羽披，其上缀有成片的金红色羽毛，整体由绒毛制成，极其轻便。<br> 本资源仅限女性购买，占据盔甲位，视为轻甲</p><p>D+750<br> 在此阶段下，永生羽衣的羽毛看起来还黯淡无光，寄宿在其上的力量尚未完全流失。<br> 永生羽衣的护甲防御为5/5<br> 【余火将熄】<br> 羽衣的力量已几乎消耗殆尽，但失去了火的时代，只能保留它最低限度的热量。穿戴这件羽衣时，使用者将获得免疫C级及以下的潮湿效果。</p><p>【东隅日暮】<br> 现在，使用者会获得一种特殊的，名为【火种】的计数方式，每经历一场影片，且其中曾进行过一次表现分为传奇的扮演，在影片结束时获得1粒【火种】。<br> 并根据拥有的【火种】数量，参照下表获得增益：<br> 1粒：羽衣的护甲防御提升使用者的传奇决心*1点。<br> 2粒：羽衣将获得免疫多次攻击带来的减值的效果。<br> 3粒：一回合一次，羽衣的使用者受到攻击时，攻击者将必须重投一次，两次结果取劣。<br> 4粒：羽衣的护甲防御提升使用者的决心点。</p><p>C+1000<br> 在此阶段下，永生羽衣已恢复了一部分光和热，行走时会在身后留下尾迹。<br> 永生羽衣在此阶段下提升8点护甲。<br> 【照我以火】<br> 羽衣的力量逐渐提升，已没有最开始般孱弱。穿戴这件羽衣时，使用者将获得免疫B级及以下的潮湿效果。</p><p>【轻灵凤羽】<br> 一轮一次，当使用者进行了一次招架时，可以应用这个能力的效果，使用者将立即视为以极其轻灵的步伐躲闪这次攻击，对于本次攻击而言，使用者视为移出了攻击者的攻击范围。</p><p>B+2000<br> 在此阶段下，【永生】将真正成为永生羽衣的代名词，相传，东方之神鸟每过一千年便要涅槃重生，而永生羽衣也不例外。<br> 永生羽衣在此阶段下提升7点护甲。<br> 【永生】<br> 在收集齐4粒火种后，一场影片一次，当使用者首次死亡时，则永生羽衣将立刻化作满天飞羽，将使用者包裹入其中，使用者将转化为灵体状态，并在一周后从羽衣中破出，以正常状态复活，这是一个A级时空来源的复活效果。<br> 【桑榆非晚】<br> 在以【永生】复活后，【桑榆非晚】将开始持续生效直至影片结束。只要使用者仍处于场景中，场景便视为亮度提升至最高，所有直接目击使用者的角色需要以意志豁免对抗DC17，若对抗失败，则其将陷入目盲状态之中，这是一个B级模因来源的目盲效果，使用者再获得完美机动性飞行。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
